import { Component, h, Prop, Element, Event, EventEmitter, State, Watch, Host } from '@stencil/core';
import { forwardCommonHostAttributes } from '../../utils/utils';
import { ButtonVariants, SurfaceVariant } from '../../components';

export type ToastStyle = 'success' | 'informational' | 'warning' | 'error';
export type ToastAction = 'button' | 'close';

@Component({
  tag: 'wdpr-toast',
  styleUrl: 'wdpr-toast.css',
  shadow: true,
})
export class WdprToast {
  private _enterRef: number | null = null;
  private _autoDismissTimer: ReturnType<typeof setTimeout> | null = null;
  private _exitFallbackTimer: ReturnType<typeof setTimeout> | null = null;
  private _exitTransitionHandler: ((e: TransitionEvent) => void) | null = null;

  @Element() el: HTMLElement;

  @State() _isEntered = false;
  @State() _isExiting = false;

  /** Toast type */
  @Prop() toastStyle: ToastStyle = 'success';

  /** Action type (button or close) */
  @Prop() actionType: ToastAction = 'close';

  /** Show description text */
  @Prop() showDescription = true;

  /** Title text */
  @Prop() toastTitle = '';

  /** Action text */
  @Prop() actionText = '';

  /** Description text */
  @Prop() description = '';

  /**
   * Auto-dismiss delay in milliseconds. Default 0 (disabled).
   * Suggested durations: 3000ms for &lt;1 line, 4000ms for 2 lines. Consider 0 for error toasts and action toasts.
   */
  @Prop() autoDismissMs = 0;

  /** Optional ARIA role for live regions (alert/status). Accepts 'alert', 'status'; any other value omits the role. */
  @Prop({ attribute: 'role', reflect: true }) role: string;

  /** Accessible label for the close icon button */
  @Prop() closeAriaLabel: string = 'Close toast';

  /** Accessible label for the inline action button (falls back to actionText) */
  @Prop() actionAriaLabel?: string;

  /** Emitted when action button or close icon is clicked */
  @Event() actionClicked!: EventEmitter<void>;

  /** Emitted after the exit animation completes (e.g. after close or auto-dismiss). Use to remove the toast from the DOM. */
  @Event() toastDismissed!: EventEmitter<void>;

  @Watch('_isEntered')
  onEnteredChange(entered: boolean) {
    if (entered) this._startAutoDismiss();
  }

  @Watch('_isExiting')
  onExitingChange(isExiting: boolean) {
    if (isExiting) {
      this._clearAutoDismiss();
      this._attachExitListener();
    }
  }

  connectedCallback() {
    this._enterRef = requestAnimationFrame(() => {
      this._enterRef = null;
      this._isEntered = true;
    });
  }

  disconnectedCallback() {
    if (this._enterRef != null) {
      cancelAnimationFrame(this._enterRef);
      this._enterRef = null;
    }
    this._clearAutoDismiss();
    this._detachExitListener();
    if (this._exitFallbackTimer != null) {
      clearTimeout(this._exitFallbackTimer);
      this._exitFallbackTimer = null;
    }
  }

  handleAction = (ev?: Event) => {
    ev?.stopPropagation?.();
    this.actionClicked.emit();
    this._isExiting = true;
  };

  /** Map ToastStyle → wdpr-surface-style variant */
  private _getSurfaceVariant() {
    const map: Record<ToastStyle, string> = {
      success: 'success-extra-bright-large-elevated',
      informational: 'informational-extra-bright-large-elevated',
      warning: 'warning-extra-bright-large-elevated',
      error: 'critical-dim-large-elevated',
    };

    return map[this.toastStyle];
  }

  private _getAccessibleLabel(style: ToastStyle): string {
    switch (style) {
      case 'success':
        return 'Success';
      case 'warning':
        return 'Warning';
      case 'informational':
        return 'Information';
      case 'error':
        return 'Error';
    }
  }

  /** Icons */
  private _getIcon() {
    return <wdpr-status-icon variant={this.toastStyle} size="xxsmall" ariaLabel={this._getAccessibleLabel(this.toastStyle)} />;
  }

  private _getButtonVariant(): ButtonVariants {
    switch (this.toastStyle) {
      case 'error':
        return 'tertiary-alt';
      default:
        return 'tertiary';
    }
  }

  /** Keep the original look, but allow wrapping on small screens */
  private _getContainerClasses() {
    return `flex flex-wrap sm:flex-nowrap ${this.showDescription ? 'items-start' : 'items-center'} gap-150 w-full`;
  }

  private _getTitleClasses() {
    return 'max-w-xs heading-xsmall-alt line-clamp-1' + (this.toastStyle === 'error' ? ' text-text-inverse' : ' text-text-heading');
  }

  private _getDescriptionClasses() {
    return 'max-w-xs body-small line-clamp-2' + (this.toastStyle === 'error' ? ' text-text-inverse' : ' text-text-body');
  }

  private _getActionClasses() {
    return `toast-close  ${this.toastStyle === 'error' ? ' text-text-inverse' : ''} `;
  }

  /** Allow content to actually shrink when space is tight */
  private _getContentClasses() {
    const wrappingClasses = this.actionType === 'button' ? 'flex-wrap sm:flex-nowrap' : '';

    return `min-w-0 flex flex-1 ${wrappingClasses} items-start gap-150`;
  }

  /** Validate role prop. Only 'alert' or 'status' are applied; anything else (including 'none') omits the role. */
  private _getValidatedRoleAttr(): { role?: 'alert' | 'status' } {
    const value = (this.role || '').trim().toLowerCase();
    if (value === 'alert' || value === 'status') {
      return { role: value };
    }

    return {};
  }

  private _clearAutoDismiss() {
    if (this._autoDismissTimer != null) {
      clearTimeout(this._autoDismissTimer);
      this._autoDismissTimer = null;
    }
  }

  private _startAutoDismiss() {
    if (this.autoDismissMs <= 0 || this._isExiting) return;
    this._autoDismissTimer = setTimeout(() => {
      this._autoDismissTimer = null;
      this._isExiting = true;
    }, this.autoDismissMs);
  }

  private _attachExitListener() {
    this._detachExitListener();
    const complete = () => {
      if (this._exitFallbackTimer != null) {
        clearTimeout(this._exitFallbackTimer);
        this._exitFallbackTimer = null;
      }
      this._detachExitListener();
      this.toastDismissed.emit();
    };
    const handler = (e: TransitionEvent) => {
      if (e.propertyName !== 'transform') return;
      complete();
    };
    this._exitTransitionHandler = handler;
    this.el.addEventListener('transitionend', handler);
    this._exitFallbackTimer = setTimeout(complete, 500);
  }

  private _detachExitListener() {
    if (this._exitTransitionHandler) {
      this.el.removeEventListener('transitionend', this._exitTransitionHandler);
      this._exitTransitionHandler = null;
    }
    if (this._exitFallbackTimer != null) {
      clearTimeout(this._exitFallbackTimer);
      this._exitFallbackTimer = null;
    }
  }

  private _getAction() {
    if (this.actionType === 'close') {
      return (
        <wdpr-icon-button
          variant={this.toastStyle === 'error' ? 'tertiary-alt' : 'primary'}
          iconName="close-reversed"
          a11yLabel={this.closeAriaLabel}
          size="xxsmall"
          class={this._getActionClasses()}
          onClick={this.handleAction}
        />
      );
    }

    return (
      <slot name="action">
        <wdpr-button variant={this._getButtonVariant()} onClick={this.handleAction} a11yLabel={this.actionAriaLabel || this.actionText} display="block" size="small">
          {this.actionText}
        </wdpr-button>
      </slot>
    );
  }

  /** When action is a button, stack it below on small screens; inline from sm and up */
  private _getActionContainerClasses() {
    if (this.actionType === 'button') {
      return 'shrink-0 w-full sm:w-auto';
    }

    return 'shrink-0';
  }

  /** Enter duration: 300ms success/informational, 200ms warning, 100ms error. */
  private _getHostClass() {
    const classes: string[] = [];
    if (this.toastStyle === 'success' || this.toastStyle === 'informational') {
      classes.push('toast-enter-300');
    } else if (this.toastStyle === 'error') {
      classes.push('toast-enter-100');
    }
    if (this._isEntered && !this._isExiting) classes.push('toast-entered');
    if (this._isExiting) classes.push('toast-exiting');

    return classes.length ? classes.join(' ') : undefined;
  }

  render() {
    // Avoid passing through any pre-existing 'role' from forwarded attributes;
    // rely on validated role only.
    const forwarded = { ...(forwardCommonHostAttributes(this.el) || {}) } as Record<string, string>;
    if ('role' in forwarded) delete forwarded.role;

    return (
      <Host class={this._getHostClass()}>
        <wdpr-surface-style {...forwarded} {...this._getValidatedRoleAttr()} variant={this._getSurfaceVariant() as SurfaceVariant} padding="md" class={this._getContainerClasses()}>
          <div class={this._getContentClasses()}>
            {/* Icon */}
            <div class="shrink-0">{this._getIcon()}</div>

            {/* Content */}
            <div class="flex-1 items-start flex flex-col gap-050 min-w-0 pt-025">
              <h2 part="title" class={this._getTitleClasses()} title={this.toastTitle || undefined}>
                {this.toastTitle}
              </h2>
              {this.showDescription && (
                <p part="description" class={this._getDescriptionClasses()} title={this.description || undefined}>
                  {this.description}
                </p>
              )}
            </div>

            {/* Action */}
            <div class={this._getActionContainerClasses()}>{this._getAction()}</div>
          </div>
        </wdpr-surface-style>
      </Host>
    );
  }
}
